SELECT id,
       user_id, name, project_id, tag, type, content, vector_ids, created_at, updated_at FROM
       knowledge_bases WHERE user_id = #{userId}  AND project_id = #{projectId} 
        AND type = #{type}  ORDER BY created_at DESC LIMIT #{limit}
       OFFSET #{offset}

SELECT COUNT(*) FROM knowledge_bases WHERE
       user_id = #{userId}  AND project_id = #{projectId} 
        AND type = #{type}
